// Load configuration from watchout.json and store in global context.
// Adjust the path to match your Node-RED working directory.
const fs = require('fs');
const path = require('path');

const configPath = path.join(__dirname, '..', 'config', 'watchout.json');
let config;
try {
    config = JSON.parse(fs.readFileSync(configPath, 'utf8'));
} catch (e) {
    node.warn('Could not load watchout.json, using defaults: ' + e.message);
    config = {};
}

global.set('watchoutConfig', config);
node.log('Watchout config loaded: ' + JSON.stringify(config));
return msg;

// Instantiate the WatchoutClient and store it in global context.
// Uses createWatchoutClient registered in settings.js functionGlobalContext.
const createWatchoutClient = global.get('createWatchoutClient');
if (!createWatchoutClient) {
    node.error('createWatchoutClient not found in global context. ' +
        'Add it to functionGlobalContext in settings.js');
    return null;
}

// Destroy any previous instance (e.g. on re-deploy)
const prev = global.get('watchout');
if (prev && typeof prev.destroy === 'function') {
    prev.destroy();
}

const wo = createWatchoutClient(global, node);
global.set('watchout', wo);

wo.init()
    .then(() => node.log('Watchout client ready'))
    .catch((err) => node.error('Watchout init error: ' + err.message));

return null;

