// Expected input:
//   msg.payload = { command: 'start'|'stop'|'pause', contentId: 'show1' }
//   OR
//   msg.payload = { command: 'start', timelineId: '1' }

const wo = global.get('watchout');
if (!wo) {
    node.error('Watchout client not initialised');
    return null;
}

const { command, contentId, timelineId, params } = msg.payload || {};

if (!command) {
    node.error('Missing command in msg.payload');
    return null;
}

let action;
if (contentId) {
    const methodMap = {
        start: wo.startByContent,
        stop:  wo.stopByContent,
        pause: wo.pauseByContent,
    };
    const method = methodMap[command];
    if (!method) {
        node.error('Unknown command: ' + command);
        return null;
    }
    action = method(contentId);
} else if (timelineId) {
    action = wo.controlTimeline(timelineId, command, params);
} else {
    node.error('Provide either contentId or timelineId in msg.payload');
    return null;
}

action
    .then((result) => {
        node.send({ topic: 'watchout/control/result', payload: result });
    })
    .catch((err) => {
        node.error('Timeline control error: ' + err.message);
        node.send({ topic: 'watchout/control/error', payload: { error: err.message } });
    });

return null;

// Expected input:
//   msg.payload = { key: 'variableName', value: <any> }

const wo = global.get('watchout');
if (!wo) {
    node.error('Watchout client not initialised');
    return null;
}

const { key, value } = msg.payload || {};

if (!key) {
    node.error('Missing key in msg.payload');
    return null;
}

if (value === undefined) {
    node.error('Missing value in msg.payload');
    return null;
}

wo.setInput(key, value)
    .then((result) => {
        node.send({ topic: 'watchout/input/result', payload: result });
    })
    .catch((err) => {
        node.error('setInput error: ' + err.message);
        node.send({ topic: 'watchout/input/error', payload: { error: err.message } });
    });

return null;

// Receives messages emitted by the WatchoutClient on state change.
// msg.topic = 'watchout/state'  → full /v0/state snapshot
// msg.topic = 'watchout/sse/*' → raw SSE event
// msg.topic = 'watchout/timelines' → updated timeline mapping

// You can fan out to other parts of the flow here.
// Example: update a dashboard status widget, drive the show controller, etc.

if (msg.topic === 'watchout/timelines') {
    node.log('Timeline mapping updated: ' + JSON.stringify(msg.payload));
} else if (msg.topic === 'watchout/state') {
    const running = (msg.payload.timelines || [])
        .filter(t => t.running)
        .map(t => t.id);
    node.log('Running timeline IDs: ' + (running.join(', ') || '(none)'));
}

return msg;
